{
    "name": "Iron Condor Weekly - Test",
    "description": "Test iron condor strategy created via Postman",
    "underlying": "NIFTY",
    "expiry_type": "current_week",
    "lots": 1,
    "position_type": "intraday",
    "legs_config": [
        {
            "id": "leg_1",
            "contract_type": "PE",
            "transaction_type": "SELL",
            "strike_selection": {
                "mode": "atm_offset",
                "offset": -200
            },
            "quantity_multiplier": 1,
            "execution_order": 1
        },
        {
            "id": "leg_2",
            "contract_type": "PE",
            "transaction_type": "BUY",
            "strike_selection": {
                "mode": "atm_offset",
                "offset": -400
            },
            "quantity_multiplier": 1,
            "execution_order": 2
        },
        {
            "id": "leg_3",
            "contract_type": "CE",
            "transaction_type": "SELL",
            "strike_selection": {
                "mode": "atm_offset",
                "offset": 200
            },
            "quantity_multiplier": 1,
            "execution_order": 3
        },
        {
            "id": "leg_4",
            "contract_type": "CE",
            "transaction_type": "BUY",
            "strike_selection": {
                "mode": "atm_offset",
                "offset": 400
            },
            "quantity_multiplier": 1,
            "execution_order": 4
        }
    ],
    "entry_conditions": {
        "logic": "AND",
        "conditions": [
            {
                "id": "cond_1",
                "enabled": true,
                "variable": "TIME.CURRENT",
                "operator": "greater_than",
                "value": "09:20"
            },
            {
                "id": "cond_2",
                "enabled": true,
                "variable": "VOLATILITY.VIX",
                "operator": "between",
                "value": [13, 18]
            }
        ]
    },
    "adjustment_rules": [
        {
            "id": "rule_1",
            "name": "Stop Loss Exit",
            "enabled": true,
            "priority": 1,
            "trigger": {
                "logic": "OR",
                "conditions": [
                    {
                        "id": "trig_1",
                        "variable": "STRATEGY.PNL",
                        "operator": "less_than",
                        "value": -5000
                    }
                ]
            },
            "action": {
                "type": "exit_all",
                "config": {
                    "order_type": "MARKET"
                }
            },
            "execution_mode": "auto",
            "timeout_seconds": 60,
            "timeout_action": "skip"
        },
        {
            "id": "rule_2",
            "name": "Profit Target Exit",
            "enabled": true,
            "priority": 2,
            "trigger": {
                "logic": "OR",
                "conditions": [
                    {
                        "id": "trig_2",
                        "variable": "STRATEGY.PNL",
                        "operator": "greater_than",
                        "value": 8000
                    }
                ]
            },
            "action": {
                "type": "exit_all",
                "config": {
                    "order_type": "MARKET"
                }
            },
            "execution_mode": "auto",
            "timeout_seconds": 60,
            "timeout_action": "skip"
        },
        {
            "id": "rule_3",
            "name": "Time Exit",
            "enabled": true,
            "priority": 3,
            "trigger": {
                "logic": "OR",
                "conditions": [
                    {
                        "id": "trig_3",
                        "variable": "TIME.CURRENT",
                        "operator": "greater_than",
                        "value": "15:15"
                    }
                ]
            },
            "action": {
                "type": "exit_all",
                "config": {
                    "order_type": "MARKET"
                }
            },
            "execution_mode": "auto",
            "timeout_seconds": 60,
            "timeout_action": "execute"
        }
    ],
    "order_settings": {
        "order_type": "MARKET",
        "execution_style": "sequential",
        "leg_sequence": ["leg_1", "leg_3", "leg_2", "leg_4"],
        "delay_between_legs": 2,
        "slippage_protection": {
            "enabled": true,
            "max_per_leg_pct": 2.0,
            "max_total_pct": 5.0,
            "on_exceed": "retry",
            "max_retries": 3
        },
        "on_leg_failure": "stop"
    },
    "risk_settings": {
        "max_loss": 10000,
        "max_loss_pct": null,
        "trailing_stop": {
            "enabled": false
        },
        "max_margin": 200000,
        "time_stop": "15:20"
    },
    "schedule_config": {
        "activation_mode": "always",
        "active_days": ["MON", "TUE", "WED", "THU", "FRI"],
        "start_time": "09:15",
        "end_time": "15:30",
        "expiry_days_only": false
    },
    "priority": 100
}

